const termine = $input.all();
const now = new Date();
const toSend = [];

// CET/CEST timezone offset berechnen
function getCETOffset(date) {
  const y = date.getUTCFullYear();
  // Letzter Sonntag im Maerz (DST start)
  const mar = new Date(Date.UTC(y, 2, 31));
  const dstStart = new Date(Date.UTC(y, 2, 31 - mar.getUTCDay(), 1, 0, 0));
  // Letzter Sonntag im Oktober (DST end)
  const oct = new Date(Date.UTC(y, 9, 31));
  const dstEnd = new Date(Date.UTC(y, 9, 31 - oct.getUTCDay(), 1, 0, 0));
  return (date >= dstStart && date < dstEnd) ? 2 : 1;
}
const tzOffset = getCETOffset(now);
const tzSuffix = '+0' + tzOffset + ':00';

for (const item of termine) {
  const d = item.json;
  if (!d.Termin_Datum || !d.Termin_Uhrzeit || !d.Telefon) continue;
  const status = (d.Status || '').toLowerCase();
  if (status === 'abgesagt' || status === 'verschoben') continue;
  const terminDate = new Date(d.Termin_Datum + 'T' + d.Termin_Uhrzeit + ':00' + tzSuffix);
  const diffMs = terminDate - now;
  const diffH = diffMs / (1000 * 60 * 60);
  const diffDays = diffH / 24;
  const uhrzeit = d.Termin_Uhrzeit;
  const name = (d.Fahrschueler_Name || '').split(' ')[0];
  const typ = d.Termin_Typ || 'Termin';
  const rowNum = d.row_number;
  const isPruefung = typ.toLowerCase().includes('pru');
  const typLabels = {'Fahrstunde':'Fahrstunde','Theorie':'Theoriestunde','Pruefung_Theorie':'Theoriepruefung','Pruefung_Praktisch':'Praktische Pruefung','Autobahn':'Autobahnfahrt','Nachtfahrt':'Nachtfahrt'};
  const typLabel = typLabels[typ] || typ;

  if (isPruefung && diffDays > 6.5 && diffDays < 7.5 && d.Erinnerung_1w !== 'ja') {
    const tipp = typ.toLowerCase().includes('theorie') ? 'Geh nochmal alle Pruefungsboegen durch.' : 'Uebe nochmal das Einparken und die Grundfahraufgaben.';
    toSend.push({ json: { number: d.Telefon, message: 'Hallo ' + name + '! In genau einer Woche ist deine ' + typLabel + '! Termin: ' + d.Termin_Datum + ' um ' + uhrzeit + ' Uhr. Tipp: ' + tipp + ' Du schaffst das!', updateCell: 'Termine!J' + rowNum, logTyp: 'Erinnerung_1w', logName: d.Fahrschueler_Name }});
  }

  if (status === 'bestaetigt' && diffH > 47 && diffH < 49 && d.Erinnerung_48h !== 'ja') {
    toSend.push({ json: { number: d.Telefon, message: 'Hallo ' + name + '! Erinnerung: Uebermorgen am ' + d.Termin_Datum + ' um ' + uhrzeit + ' Uhr hast du ' + typLabel + '. Bitte beachte: Absagen sind nur bis 48h vorher kostenlos moeglich. Kannst du den Termin wahrnehmen?', updateCell: 'Termine!K' + rowNum, logTyp: 'Erinnerung_48h', logName: d.Fahrschueler_Name }});
  }

  if (status === 'bestaetigt' && diffH > 23 && diffH < 25 && d.Erinnerung_24h !== 'ja') {
    let extra = isPruefung ? ' Vergiss nicht: Personalausweis mitnehmen!' : '';
    toSend.push({ json: { number: d.Telefon, message: 'Hallo ' + name + '! Erinnerung: Morgen um ' + uhrzeit + ' Uhr hast du ' + typLabel + '. Bitte sei 5 Minuten vorher da.' + extra + ' Falls du nicht kannst, sag bitte JETZT Bescheid!', updateCell: 'Termine!L' + rowNum, logTyp: 'Erinnerung_24h', logName: d.Fahrschueler_Name }});
  }

  if (status === 'bestaetigt' && diffH > 1.5 && diffH < 2.5 && d.Erinnerung_2h !== 'ja') {
    const kurz = isPruefung ? 'Bleib ruhig und konzentriert. Du bist gut vorbereitet!' : 'Bis gleich!';
    toSend.push({ json: { number: d.Telefon, message: 'Hi ' + name + '! In 2 Stunden gehts los: ' + typLabel + ' um ' + uhrzeit + ' Uhr. ' + kurz, updateCell: 'Termine!M' + rowNum, logTyp: 'Erinnerung_2h', logName: d.Fahrschueler_Name }});
  }

  const dauerMin = parseInt(d.Termin_Dauer_Min) || 90;
  const terminEnde = new Date(terminDate.getTime() + dauerMin * 60000);
  const nachDiffH = (now - terminEnde) / (1000 * 60 * 60);
  if (status === 'abgeschlossen' && nachDiffH > 1.5 && nachDiffH < 3 && d.Nachbereitung_gesendet !== 'ja') {
    if (isPruefung && d.Pruefung_Ergebnis === 'bestanden') {
      toSend.push({ json: { number: d.Telefon, message: 'HERZLICHEN GLUECKWUNSCH ' + name + '! Du hast deine ' + typLabel + ' BESTANDEN! Wir sind mega stolz auf dich!', updateCell: 'Termine!N' + rowNum, logTyp: 'Pruefung_Bestanden', logName: d.Fahrschueler_Name }});
    } else if (isPruefung && d.Pruefung_Ergebnis === 'nicht_bestanden') {
      toSend.push({ json: { number: d.Telefon, message: 'Hi ' + name + ', Kopf hoch! Das passiert vielen. Wir bereiten dich noch besser vor. Beim naechsten Mal packst du das! Melde dich fuer einen neuen Termin.', updateCell: 'Termine!N' + rowNum, logTyp: 'Pruefung_Nicht_Bestanden', logName: d.Fahrschueler_Name }});
    } else if (!isPruefung) {
      toSend.push({ json: { number: d.Telefon, message: 'Hi ' + name + '! Wie war deine heutige ' + typLabel + '? Hast du Fragen oder Feedback? Uebung macht den Meister! Bis zum naechsten Mal!', updateCell: 'Termine!N' + rowNum, logTyp: 'Nachbereitung', logName: d.Fahrschueler_Name }});
    }
  }

  if (status === 'bestaetigt' && diffH < -1 && diffH > -2 && d.No_Show_gesendet !== 'ja') {
    toSend.push({ json: { number: d.Telefon, message: 'Hi ' + name + ', wir haben dich heute um ' + uhrzeit + ' Uhr zu deiner ' + typLabel + ' erwartet. Ist alles in Ordnung? Bitte melde dich bei uns fuer einen neuen Termin.', updateCell: 'Termine!Q' + rowNum, logTyp: 'No_Show', logName: d.Fahrschueler_Name }});
  }

  if (isPruefung && d.Pruefung_Ergebnis === 'bestanden' && d.Nachbereitung_gesendet === 'ja' && d.Bewertung_angefragt !== 'ja' && nachDiffH > 23 && nachDiffH < 25) {
    toSend.push({ json: { number: d.Telefon, message: 'Hi ' + name + '! Nochmal herzlichen Glueckwunsch! Wuerdest du uns eine Google-Bewertung hinterlassen? https://g.page/r/DEINE-FAHRSCHULE/review Vielen Dank!', updateCell: 'Termine!P' + rowNum, logTyp: 'Bewertung_Angefragt', logName: d.Fahrschueler_Name }});
  }
}

return toSend;

const items = $input.all();
const now = new Date().toLocaleString('de-DE', {timeZone: 'Europe/Berlin'});
const results = [];
for (const item of items) {
  const d = item.json;
  results.push({ json: { Timestamp: now, Typ: d.logTyp || '', Fahrschueler: d.logName || '', Telefon: d.number || '', Nachricht: (d.message || '').substring(0, 100) + '...', Status: 'gesendet' } });
}
return results;
